import { CronJob } from "cron";
import { HttpUtilsError } from "../error.js";
export function cronify(func, cronExpression, runOnInit) {
    return async () => {
        try {
            CronJob.from({
                cronTime: cronExpression,
                onTick: func,
                start: true,
                timeZone: null,
                runOnInit: runOnInit,
            });
        }
        catch (e) {
            throw HttpUtilsError.invalidCronExpression();
        }
    };
}
